import React from 'react';

const AIAssistant = () => {
  // For now, static suggestions. Later, make it dynamic based on current calculator.
  const suggestions = [
    { type: 'warning', text: '⚠️ Your EMI is too high. Consider reducing loan amount.' },
    { type: 'info', text: '💡 Consider higher return investment options.' },
    { type: 'success', text: '✅ Your salary is in good range.' }
  ];

  return (
    <div className="w-80 bg-gradient-to-b from-slate-800 to-slate-900 shadow-lg p-6 overflow-y-auto">
      <h3 className="text-xl font-bold mb-6 bg-gradient-to-r from-purple-400 to-pink-400 bg-clip-text text-transparent">
        AI Assistant
      </h3>
      <div className="space-y-4">
        {suggestions.map((suggestion, index) => (
          <div
            key={index}
            className={`p-4 rounded-lg backdrop-blur-sm border ${
              suggestion.type === 'warning'
                ? 'bg-red-500/20 border-red-500/30'
                : suggestion.type === 'info'
                ? 'bg-blue-500/20 border-blue-500/30'
                : 'bg-green-500/20 border-green-500/30'
            }`}
          >
            <p className="text-sm">{suggestion.text}</p>
          </div>
        ))}
      </div>
      <div className="mt-6">
        <h4 className="text-lg font-semibold mb-2">Business Health Score</h4>
        <div className="bg-slate-700 rounded-full h-4 mb-2">
          <div className="bg-gradient-to-r from-green-400 to-blue-500 h-4 rounded-full" style={{ width: '75%' }}></div>
        </div>
        <p className="text-sm">75/100 - Good</p>
      </div>
    </div>
  );
};

export default AIAssistant;
